    26→static std::string GetHostName(const std::string& ip)
    27→{
    28→    struct sockaddr_in addr;
    29→    struct hostent *host;
    30→    if (inet_aton(ip.c_str(), &addr.sin_addr) != 0)
    31→    {
    32→        host = gethostbyaddr((char*)&addr.sin_addr, 4, AF_INET); 
    33→    }
    34→    else
    35→    {
    36→        host = gethostbyname(ip.c_str());
    37→    }
    38→    if (host != NULL)
    39→    {
    40→        return host->h_name;
    41→    }
    42→    else
    43→    {
    44→        return ip;
    45→    }
    46→}
    47→
    48→template <class T>
    49→std::string format_number(T num)
    50→{
    51→    std::ostringstream oss;
    52→    oss << num;
    53→    std::string str = oss.str();
    54→    size_t len = str.size();
    55→    std::string ret;
    56→    for (size_t i = 0; i < str.size(); ++i)
    57→    {
    58→        if (i != 0 && len % 3 == 0)
    59→        {
    60→            ret.push_back(',');
    61→        }
    62→        ret.push_back(str.at(i));
    63→        --len;
    64→    }
    65→    return ret;
    66→}
