    99→void HTTPRpcRequest::ProcessRequest(
   100→        const RpcServerStreamWPtr& server_stream,
   101→        const ServicePoolPtr& service_pool)
   102→{
   103→    std::string service_name;
   104→    std::string method_name;
   105→    if (!ParseMethodFullName(_method, &service_name, &method_name))
   106→    {
   107→        if (RoutePage(server_stream, service_pool))
   108→        {
   109→            return;
   110→        }
   111→        else
   112→        {
   113→#if defined( LOG )
   114→            LOG(ERROR) << "ProcessRequest(): " << RpcEndpointToString(_remote_endpoint)
   115→                       << ": {" << SequenceId() << "}: method not found: " << _method;
   116→#else
   117→            SLOG(ERROR, "ProcessRequest(): %s: {%lu}: method not found: %s",
   118→                    RpcEndpointToString(_remote_endpoint).c_str(), SequenceId(), _method.c_str());
   119→#endif
   120→            SendFailedResponse(server_stream,
   121→                    RPC_ERROR_FOUND_METHOD, "method not found: " + _method);
   122→            return;
   123→        }
   124→    }
   125→
   126→    std::string json_str;
   127→    if (_type == POST)
   128→    {
   129→        json_str = _req_body->ToString();
   130→    }
   131→    else
   132→    {
   133→        json_str = _query_params["request"];
   134→    }
   135→    if (json_str.empty())
   136→    {
   137→        // if null json str, set as null object
   138→        json_str = "{}";
   139→    }
   140→
   141→    std::string err;
   142→    _req_json = ParseJson(json_str.c_str(), err);
   143→    if (_req_json == NULL)
   144→    {
   145→#if defined( LOG )
   146→        LOG(ERROR) << "ProcessRequest(): " << RpcEndpointToString(_remote_endpoint)
   147→                   << ": {" << SequenceId() << "}: parse json failed: " << err;
   148→#else
   149→        SLOG(ERROR, "ProcessRequest(): %s: {%lu}: parse json failed: %s",
   150→                RpcEndpointToString(_remote_endpoint).c_str(), SequenceId(), err.c_str());
   151→#endif
   152→        SendFailedResponse(server_stream,
   153→                RPC_ERROR_PARSE_REQUEST_MESSAGE, "parse json failed: " + err);
   154→        return;
   155→    }
   156→
   157→    MethodBoard* method_board = FindMethodBoard(service_pool, service_name, method_name);
   158→    if (method_board == NULL)
   159→    {
   160→#if defined( LOG )
   161→        LOG(ERROR) << "ProcessRequest(): " << RpcEndpointToString(_remote_endpoint)
   162→                   << ": {" << SequenceId() << "}: method not found: " << _method;
   163→#else
   164→        SLOG(ERROR, "ProcessRequest(): %s: {%lu}: method not found: %s",
   165→                RpcEndpointToString(_remote_endpoint).c_str(), SequenceId(), _method.c_str());
   166→#endif
   167→        SendFailedResponse(server_stream,
   168→                RPC_ERROR_FOUND_METHOD, "method not found: " + _method);
   169→        return;
   170→    }
   171→
   172→    google::protobuf::Service* service = method_board->GetServiceBoard()->Service();
   173→    const google::protobuf::MethodDescriptor* method_desc = method_board->Descriptor();
   174→
   175→    google::protobuf::Message* request = service->GetRequestPrototype(method_desc).New();
   176→    if (jsonobject2pb(_req_json, request, err) < 0)
   177→    {
   178→#if defined( LOG )
   179→        LOG(ERROR) << "ProcessRequest(): " << RpcEndpointToString(_remote_endpoint)
   180→                   << ": {" << SequenceId() << "}: parse json to pb failed: " << err;
   181→#else
   182→        SLOG(ERROR, "ProcessRequest(): %s: {%lu}: parse json to pb failed: %s",
   183→                RpcEndpointToString(_remote_endpoint).c_str(), SequenceId(), err.c_str());
   184→#endif
   185→        SendFailedResponse(server_stream,
   186→                RPC_ERROR_PARSE_REQUEST_MESSAGE, "parse json to pb failed: " + err);
   187→        return;
   188→    }
   189→
   190→    google::protobuf::Message* response = service->GetResponsePrototype(method_desc).New();
   191→
   192→    RpcController* controller = new RpcController();
   193→    const RpcControllerImplPtr& cntl = controller->impl();
   194→    cntl->SetSequenceId(0);
   195→    cntl->SetMethodId(_method);
   196→    cntl->SetLocalEndpoint(_local_endpoint);
   197→    cntl->SetRemoteEndpoint(_remote_endpoint);
   198→    cntl->SetRpcServerStream(server_stream);
   199→    cntl->SetRequestReceivedTime(_received_time);
   200→    cntl->SetStartProcessTime(ptime_now());
   201→    cntl->SetResponseCompressType(CompressTypeNone);
   202→
   203→    CallMethod(method_board, controller, request, response);
   204→}
   205→
   206→ReadBufferPtr HTTPRpcRequest::AssembleSucceedResponse(
   207→        const RpcControllerImplPtr& /*cntl*/,
   208→        const google::protobuf::Message* response,
   209→        std::string& err)
   210→{
   211→    std::string json_str;
   212→    pb2json(response, json_str);
   213→
   214→    WriteBuffer write_buffer;
   215→    if (!RenderJsonResponse(&write_buffer, json_str))
   216→    {
   217→        err = "render json response failed";
   218→        return ReadBufferPtr();
   219→    }
   220→
   221→    ReadBufferPtr read_buffer(new ReadBuffer());
   222→    write_buffer.SwapOut(read_buffer.get());
   223→    return read_buffer;
   224→}
   225→
   226→ReadBufferPtr HTTPRpcRequest::AssembleFailedResponse(
   227→        int32 error_code,
   228→        const std::string& reason,
   229→        std::string& err)
   230→{
   231→    std::ostringstream oss;
   232→    oss << "\"ERROR: " << error_code << ": "
   233→        << StringUtils::replace_all(reason, "\"", "\\\"") << "\"";
   234→
   235→    WriteBuffer write_buffer;
   236→    if (!RenderJsonResponse(&write_buffer, oss.str()))
   237→    {
   238→        err = "render json response failed";
   239→        return ReadBufferPtr();
   240→    }
   241→
   242→    ReadBufferPtr read_buffer(new ReadBuffer());
   243→    write_buffer.SwapOut(read_buffer.get());
   244→    return read_buffer;
   245→}
   246→
   247→bool HTTPRpcRequest::ParsePath()
   248→{
   249→    if (_path.empty() || _path[0] != '/')
   250→    {
   251→        return false;
   252→    }
   253→    // decode
   254→    _decoded_path = StringUtils::decode_url(_path,
   255→            (StringUtils::E_DECODE_RESERVED_CHAR | StringUtils::E_DECODE_PERCENT_SIGN_CHAR));
   256→#if defined( LOG )
   257→#else
   258→        SLOG(DEBUG, "ParsePath(): path=[%s], decoded_path=[%s]",
   259→                _path.c_str(), _decoded_path.c_str());
   260→#endif
   261→    // parse method
   262→    size_t start = 1; // skip first '/'
   263→    size_t end = _decoded_path.size();
   264→    for (size_t i = start; i != end; ++i)
   265→    {
   266→        if (_decoded_path[i] == '?' || _decoded_path[i] == '#')
   267→        {
   268→            end = i;
   269→            break;
   270→        }
   271→    }
   272→    _method = _decoded_path.substr(start, end - start);
   273→    // parse query
   274→    if (end < _decoded_path.size() && _decoded_path[end] == '?')
   275→    {
   276→        start = end + 1;
   277→        end = _decoded_path.size();
   278→        for (size_t i = start; i != end; ++i)
   279→        {
   280→            if (_decoded_path[i] == '#')
   281→            {
   282→                end = i;
   283→                break;
   284→            }
   285→        }
   286→        _query_string = _decoded_path.substr(start, end - start);
   287→        if (!_query_string.empty())
   288→        {
   289→            std::vector<std::string> param_list;
   290→            StringUtils::split(_query_string, "&", &param_list);
   291→            for (size_t i = 0; i < param_list.size(); ++i)
   292→            {
   293→                const std::string& param = param_list[i];
   294→                std::string::size_type pos = param.find('=');
   295→                if (pos != std::string::npos)
   296→                {
   297→                    std::string key = param.substr(0, pos);
   298→                    std::string value = param.substr(pos + 1);
   299→                    _query_params[key] = value;
   300→                }
   301→            }
   302→        }
   303→    }
   304→    // parse fragment
   305→    if (end < _decoded_path.size() && _decoded_path[end] == '#')
   306→    {
   307→        _fragment_id = _decoded_path.substr(end + 1);
   308→    }
   309→    return true;
   310→}
   311→
   312→bool HTTPRpcRequest::RoutePage(
   313→        const RpcServerStreamWPtr& server_stream,
   314→        const ServicePoolPtr& service_pool)
   315→{
   316→    if (_method == "" || _method == "home")
   317→    {
   318→        std::ostringstream oss;
   319→        PageHeader(oss);
   320→        ServerBrief(oss, service_pool);
   321→        ServerStatus(oss, service_pool);
   322→        ServiceList(oss, service_pool);
   323→        ServerOptions(oss, service_pool);
   324→        PageFooter(oss);
   325→        SendPage(server_stream, oss.str());
   326→        return true;
   327→    }
   328→    else if (_method == "options")
   329→    {
   330→        std::ostringstream oss;
   331→        PageHeader(oss);
   332→        oss << "<a href=\"/\">&lt;&lt;&lt;&lt;back to Home</a><br>";
   333→        ServerOptions(oss, service_pool);
   334→        PageFooter(oss);
   335→        SendPage(server_stream, oss.str());
   336→        return true;
   337→    }
   338→    else if (_method == "status")
   339→    {
   340→        std::ostringstream oss;
   341→        PageHeader(oss);
   342→        oss << "<a href=\"/\">&lt;&lt;&lt;&lt;back to Home</a><br>";
   343→        ServerStatus(oss, service_pool);
   344→        PageFooter(oss);
   345→        SendPage(server_stream, oss.str());
   346→        return true;
   347→    }
   348→    else if (_method == "services")
   349→    {
   350→        std::ostringstream oss;
   351→        PageHeader(oss);
   352→        oss << "<a href=\"/\">&lt;&lt;&lt;&lt;back to Home</a><br>";
   353→        ServiceList(oss, service_pool);
   354→        PageFooter(oss);
   355→        SendPage(server_stream, oss.str());
   356→        return true;
   357→    }
   358→    else if (_method == "service")
   359→    {
   360→        if (_query_params.find("name") == _query_params.end())
   361→        {
   362→            SendError(server_stream, "Lack of name param");
   363→            return true;
   364→        }
   365→        ServiceBoard* svc_board = service_pool->FindService(_query_params["name"]);
   366→        if (svc_board == NULL)
   367→        {
   368→            SendError(server_stream, "Service not found");
   369→            return true;
   370→        }
   371→        std::ostringstream oss;
   372→        PageHeader(oss);
   373→        oss << "<a href=\"/\">&lt;&lt;&lt;&lt;back to Home</a><br>"
   374→            << "<a href=\"/services\">&lt;&lt;&lt;&lt;back to Services</a>";
   375→        MethodList(oss, svc_board);
   376→        PageFooter(oss);
   377→        SendPage(server_stream, oss.str());
   378→        return true;
   379→    }
   380→    return false;
   381→}
