   383→void HTTPRpcRequest::SendPage(
   384→        const RpcServerStreamWPtr& server_stream,
   385→        const std::string& page)
   386→{
   387→    WriteBuffer write_buffer;
   388→    if (!RenderHtmlResponse(&write_buffer, page))
   389→    {
   390→#if defined( LOG )
   391→        LOG(ERROR) << "SendPage(): " << RpcEndpointToString(_remote_endpoint)
   392→                   << ": {" << SequenceId() << "}"
   393→                   << ": render response failed";
   394→#else
   395→        SLOG(ERROR, "SendPage(): %s: {%lu}: render response failed",
   396→                RpcEndpointToString(_remote_endpoint).c_str(), SequenceId());
   397→#endif
   398→        return;
   399→    }
   400→
   401→    ReadBufferPtr read_buffer(new ReadBuffer());
   402→    write_buffer.SwapOut(read_buffer.get());
   403→
   404→    SendSucceedResponse(server_stream, read_buffer);
